PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?athlete ?athleteLabel
WHERE {
  ?event wdt:P31 wd:Q13543 ;
         wdt:P445 wd:Q136393795 .
  ?medal wdt:P266 ?event ;
         wdt:P31 wd:Q3588745 .
  ?athlete wdt:P166 ?medal .
  ?athlete rdfs:label ?athleteLabel .
  FILTER (langMatches(lang(?athleteLabel), "en"))
}
LIMIT 1

